const results = [];
const currentItems = $input.all();
const originalItems = $('Clean Notion Content').all();
for (let i = 0; i < currentItems.length; i++) {
  const current = currentItems[i].json;
  const original = originalItems[i].json;
  let category = 'Other';
  let executive_summary = {};
  const raw = current.response || current.content || '';
  let jsonStr = raw.trim();
  const firstBrace = jsonStr.indexOf('{');
  const lastBrace = jsonStr.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
    jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
  }
  jsonStr = jsonStr.replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"');
  try {
    const parsed = JSON.parse(jsonStr);
    category = parsed.category || 'Other';
    executive_summary = parsed.executive_summary || {};
  } catch (e) {
    if (raw) category = raw.trim().substring(0, 50);
  }
  results.push({
    json: {
      ...original,
      category,
      executive_summary: JSON.stringify(executive_summary)
    }
  });
}
return results;

